use std::fs::File;
use std::io::{self, Read};
use anyhow::{Result, anyhow};
use std::collections::HashMap;

struct ConfigManager {
    settings: HashMap<String, String>,
}

impl ConfigManager {
    fn new() -> Self {
        ConfigManager {
            settings: HashMap::new(),
        }
    }

    fn load_config(&mut self, file_path: &str) -> Result<()> {
        println!("Attempting to read file: {}", file_path);
        let mut file = match File::open(file_path) {
            Ok(f) => f,
            Err(e) => return Err(anyhow::anyhow!("Failed to open config file {}: {}", file_path, e)),
        };

        let mut contents = String::new();
        match file.read_to_string(&mut contents) {
            Ok(_) => {
                println!("Successfully read contents from {}", file_path);
                self.settings.insert(file_path.to_string(), contents.trim().to_string());
                Ok(())
            }
            Err(e) => Err(anyhow::anyhow!("Error reading entire contents of {}: {}", file_path, e)),
        }
    }
}

fn main() -> Result<()> {
    let mut manager = ConfigManager::new();

    manager.load_config("valid_config.txt")?;
    manager.load_config("non_existent_file.cfg")?;

    Ok(()) 
}

