use anyhow::{Result, anyhow};
use std::fs;
use std::io::{self, Write};

struct LsmBackend {
    file_path: String,
}

impl LsmBackend {
    fn new(path: &str) -> Self {
        LsmBackend { file_path: path.to_string() }
    }

    fn append_data(&self, key: &str, value: &str) -> Result<()> {
        let mut file = fs::OpenOptions::new()
            .write(true)
            .append(true)
            .open(&self.file_path)?;
        writeln!(file, "{}: {}", key, value).map_err(|e| anyhow!(e))?; 
        Ok(())
    }

    fn read_all_chunks(&self) -> Result<Vec<(String, String)>> {
        let content = fs::read_to_string(&self.file_path)?;
        let mut records = Vec::new();
        for line in content.lines() {
            if let Some((key, value)) = line.split_once(':') {
                records.push((key.to_string(), value.to_string()));
            }
        }
        Ok(records)
    }
}

fn main() -> Result<()> {
    let backend = LsmBackend::new("storage_log.txt");
    backend.append_data("user_id", "12345")?;
    backend.append_data("session_key", "abcde")?;

    match backend.read_all_chunks() {
        Ok(records) => {
            println!("Successfully read {} records.", records.len());
            for (key, value) in records {
                println!("Processing -> Key: \"{}\", Value: \"{}\"", key, value); 
            }
        },
        Err(e) => {
            eprintln!("Failed to read all data chunks: {}", e);
            return Err(e);
        }
    }

    Ok(())
}

use anyhow::{Result}; 

struct DataPoint { 
    dimensions: Vec<f64>, 
    weights: Vec<f64> 
}

fn calculate_robust_average(data_points: &[DataPoint]) -> Result<Vec<f64>> {
    let num_dimensions = data_points.get(0).map(|dp| dp.dimensions.len()).unwrap_or(0);
    if num_dimensions == 0 {
        return Err(anyhow::anyhow!("Input must have at least one dimension"));
    }

    let mut aggregated_averages = vec![0.0; num_dimensions];
    let mut total_valid_points = 0;

    for point in data_points { 
        if point.dimensions.len() != num_dimensions || point.weights.len() != num_dimensions {
            return Err(anyhow::anyhow!("Dimension mismatch detected across input set"));
        }

        let mut weighted_sum = 0.0;
        for i in 0..num_dimensions {
            if point.dimensions[i].is_nan() || point.weights[i].is_nan() {
                return Err(anyhow::anyhow!("NaN encountered at dimension {} during calculation.", i));
            }
            weighted_sum += point.dimensions[i] * point.weights[i];
        }

        let average = weighted_sum / point.weights.iter().sum::<f64>();
        for i in 0..num_dimensions {
            aggregated_averages[i] += average;
        }
        total_valid_points += 1;
    }

    if total_valid_points == 0 {
        return Err(anyhow::anyhow!("No valid data points provided for averaging."));
    }

    let final_averages: Vec<f64> = aggregated_averages.into_iter().map(|s| s / (total_valid_points as f64)).collect();
    Ok(final_averages)
}

fn main() -> Result<()> {
    let good_data = vec![ 
        DataPoint { dimensions: vec![1.0, 2.0], weights: vec![0.5, 0.5] }, 
        DataPoint { dimensions: vec![3.0, 4.0], weights: vec![1.0, 1.0] }
    ];

    match calculate_robust_average(&good_data) {
        Ok(averages) => println!("Successfully calculated averages: {:?}", averages),
        Err(e) => eprintln!("Error during calculation (should not happen here): {:?}", e),
    }

    let bad_data = vec![ 
        DataPoint { dimensions: vec![1.0, f64::NAN], weights: vec![0.5, 0.5] }, 
    ];

    match calculate_robust_average(&bad_data) {
        Ok(_) => println!("Unexpected success."),
        Err(e) => eprintln!("Caught expected error: {}", e),
    }

    Ok(())
}

use anyhow::{Result, anyhow};
use std::error::Error;
use std::fmt;

struct PublicKey {}

impl PublicKey {
    fn new() -> Result<Self> {
        Ok(PublicKey {})
    }
}

trait KeyEncapsulator {
    fn encapsulate(&self, pub_key: &PublicKey) -> Result<String>;
}

struct KyberModuleImpl;

impl KeyEncapsulator for KyberModuleImpl {
    fn encapsulate(&self, pub_key: &PublicKey) -> Result<String> {
        if std::env::var("SIMULATE_FAILURE").is_ok() {
            return Err(anyhow::anyhow!("Invalid key length provided for encapsulation."));
        }
        Ok("EncapsulatedSecretObject".to_string())
    }
}

fn process_key_module() -> Result<()> {
    let public_object = PublicKey::new()?;
    let encapsulator = KyberModuleImpl;

    let secret = encapsulator.encapsulate(&public_object)?;

    println!("Successfully processed key module. Secret received: {}", secret);
    Ok(())
}

fn main() {
    if let Err(e) = process_key_module() {
        eprintln!("An error occurred during key processing: {:?}", e);
    }
}
